			<script type="text/javascript">
        jQuery(document).ready(function($) {
            // Force confirm button handler
            $(document).on('click', '#rsssl-force-confirm', function(e) {
                e.preventDefault();
                var button = $(this);
                button.prop('disabled', true);

                $.ajax({
                    url: ajaxurl,
                    type: 'POST',
                    data: {
                        action: 'rsssl_force_confirm_email',
                        rsssl_force_email_action_nonce: '38c785baf2'
                    },
                    success: function(response) {
                        if (response.success) {
                            location.reload();
                        }
                    }
                });
            });

            // Resend verification email button handler
            $(document).on('click', '#rsssl-resend-verification', function(e) {
                e.preventDefault();
                var button = $(this);
                button.prop('disabled', true);
                button.text('Sending...');

                $.ajax({
                    url: ajaxurl,
                    type: 'POST',
                    data: {
                        action: 'rsssl_resend_verification_email',
                        rsssl_resend_email_nonce: 'e059f01e75'
                    },
                    success: function(response) {
                        if (response.success) {
                            button.text('Email sent!');
                            setTimeout(function() {
                                button.text('Resend verification email');
                                button.prop('disabled', false);
                            }, 3000);
                        } else {
                            button.text('Failed to send');
                            setTimeout(function() {
                                button.text('Resend verification email');
                                button.prop('disabled', false);
                            }, 3000);
                        }
                    },
                    error: function() {
                        button.text('Error occurred');
                        setTimeout(function() {
                            button.text('Resend verification email');
                            button.prop('disabled', false);
                        }, 3000);
                    }
                });
            });
        });
	</script>
