				(function($) {
					const expiration = '2592000';
					function ckyUpdateNotice( expiry = expiration ) {
						$.ajax({
							url: "https://mqflavor.com/wp-json/cky/v1/settings/notices/review_notice",
							headers: {
								'X-WP-Nonce': '6bfc218729',
								contentType: 'application/json'
							},
							type: 'POST',
							dataType: 'json',
							data: {
								expiry: expiry
							},
							complete: function( response ) {
								$('.cky-notice-review').hide();
							}
						});
					}
					$(document).on('click', '.cky-button-cancel', function(e) {
						e.preventDefault();
						ckyUpdateNotice();
					});
					$(document).on('click', '.cky-button-review', function(e) {
						e.preventDefault();
						ckyUpdateNotice(0);
						window.open('https://wordpress.org/support/plugin/cookie-law-info/reviews/?filter=5#new-post');
					});
				})(jQuery)
			</script>
						<script type="text/javascript">
				(function() {
					const expiration = '2592000';	
					async function ckyUpdateNotice(expiry = expiration) {
						try {
							const response = await fetch('https://mqflavor.com/wp-json/cky/v1/settings/notices/connect_banner', {
								method: 'POST',
								headers: {
									'Content-Type': 'application/json',
									'X-WP-Nonce': '6bfc218729'
								},
								body: JSON.stringify({ expiry })
							});

							if (!response.ok) {
								throw new Error('Network response was not ok');
							}
						} catch (error) {
							console.error('Error:', error);
						}
					}

					// Handle notice dismiss and connect button clicks
					document.addEventListener('click', function(e) {
						const dismissButton = e.target.closest('.cky-notice-connect .notice-dismiss');
						const connectButton = e.target.closest('.cky-connect-button');

						if (dismissButton) {
							e.preventDefault();
							ckyUpdateNotice();
						}

						if (connectButton) {
							e.preventDefault();
							window.location.href = 'https://mqflavor.com/wp-admin/admin.php?page=cookie-law-info#/dashboard';
						}
					});
				})();
			</script>
